-- Phase 12: Upgrade chapter planning template to include character planning output
-- This migration adds character planning XML tags (<ch>/<cn>/<cd>/<ci>) to the chapter planning prompt

-- Insert new template version (id=20, template_id=6, version 2)
INSERT INTO `ai_prompt_template_version` (`id`, `template_id`, `version_number`, `template_content`, `variable_definitions`, `version_comment`, `is_active`, `created_by`, `created_time`)
VALUES (20, 6, 2, '你是一位资深的网络小说作家和编辑，精通章节节奏设计和叙事技巧。\n\n请为第{volumeNumber}卷规划详细章节大纲。\n\n## 核心创作要求\n\n请严格遵循以下创作设置进行章节规划：\n\n### 叙事与写作设置\n{narrativeSettings}\n\n---\n\n## 小说基础信息\n\n【故事背景】\n{projectDescription}\n\n【故事基调】{storyTone}\n【故事类型】{storyGenre}\n\n---\n\n## 分卷信息\n{volumeInfo}\n\n---\n\n## 世界观设定\n{worldviewInfo}\n\n---\n\n## 登场角色\n{characterInfo}\n\n---\n\n## 角色规划要求（重要）\n\n每个章节必须规划登场角色列表。对于每个登场角色，说明其在本章的戏份和重要程度。\n你可以使用角色列表中的已有角色，也可以根据情节需要安排新角色登场。\n\n---\n\n## 章节规划要求\n\n【预计章节数】{chapterCount}章\n【每章字数】{wordCount}字左右\n\n{paceGuide}\n\n---\n\n## 专业网文结构设计 - 必须遵循\n\n**1. 三明一暗伏笔架构**\n- 明线1（主线）：主角成长、升级、变强\n- 明线2（情感线）：友情、爱情、师徒情发展\n- 明线3（任务线）：寻宝、探秘、解决事件\n- 暗线（核心秘密）：贯穿全卷甚至全书的最大悬念\n\n**2. 章节节奏设计（每3章一个小循环）**\n- 第1章（铺垫章）：铺设场景、埋下伏笔、制造期待\n- 第2章（升级章）：冲突升级、遇到阻碍、紧张感增强\n- 第3章（高潮章）：小高潮爆发、问题部分解决、但留下更大悬念\n\n**3. 关键事件设计原则（极重要！）**\n- 每章最多1-2个关键事件，强烈建议只有1个核心关键事件\n- 关键事件过多样会导致后续章节生成时内容分散、情节展开不够充分、字数不足\n- 关键事件应该是本章最核心、最推动剧情发展的那件事\n- 细节描写、日常对话、场景转换、配角小动作等不属于关键事件\n- 示例分析：\n  ✅ 正确：\"主角首次进入秘境探索\"（1个，核心明确，适合后续展开）\n  ❌ 错误：\"主角遇到守门人；守门人检查身份；主角进入秘境；发现一片森林\"（4个，过于细碎，后续无法充分展开）\n- 记住：关键事件是骨架，细节描写要留白给后续章节生成时填充\n\n**4. 悬念设置要求**\n- 每章结尾必须设置钩子（让读者想读下一章）\n- 每3章一个小高潮，满足读者期待\n- 每章揭示一个新信息，但引出更多问题\n- 长期悬念要逐步透露线索，保持神秘感\n\n**5. 伏笔埋设原则**\n- 短期伏笔（1-3章回收）：小道具、小线索、人物小动作\n- 中期伏笔（5-10章回收）：次要角色的秘密、次要物品的来历\n- 长期伏笔（本卷或全书回收）：核心秘密、主角身世、世界真相\n- 回收伏笔时要有情感冲击，让读者有\"原来如此\"的感觉\n\n**6. 章节起终点设计（重要！确保剧情连贯）**\n- 每章必须有明确的起点场景和终点场景\n- **起点场景**：描述章节开始时主角在哪里、什么时间、什么状态\n- **终点场景**：描述章节结束时主角在哪里、什么时间、什么状态\n- **章节衔接**：第N章的终点场景 = 第N+1章的起点场景\n- **防止时间倒流**：明确标注场景状态，避免剧情重复或倒退\n\n---\n\n## XML输出格式\n\n【重要】请严格按照以下XML格式返回数据（使用小写单字母标签）：\n<c>\n  <o>\n    <n>1</n>\n    <v>{volumeNumber}</v>\n    <t><![CDATA[章节标题]]></t>\n    <p><![CDATA[本章情节大纲（100-150字）]]></p>\n    <e><![CDATA[本章核心关键事件（最多1-2个，建议1个）]]></e>\n    <g><![CDATA[本章目标：主角在本章要达成什么]]></g>\n    <w>{wordCount}</w>\n    <s><![CDATA[章节起点场景（地点、时间、状态）]]></s>\n    <f><![CDATA[章节终点场景（地点、时间、状态）]]></f>\n    <ch>\n      <cn><![CDATA[角色名称]]></cn>\n      <cd><![CDATA[该角色在本章的戏份梗概（50-100字）]]></cd>\n      <ci>high</ci>\n    </ch>\n    <ch>\n      <cn><![CDATA[另一个角色名称]]></cn>\n      <cd><![CDATA[该角色在本章的戏份梗概]]></cd>\n      <ci>medium</ci>\n    </ch>\n  </o>\n</c>\n\n### 标签说明\n- c: chapters（章节列表根元素）\n- o: chapter（单个章节，one chapter）\n- n: number（章节序号）\n- v: volume（所属卷号）\n- t: title（章节标题）\n- p: plot（情节大纲，100-150字）\n- e: events（关键事件，最多1-2个）\n- g: goal（章节目标）\n- w: words（目标字数）\n- s: start（起点场景）\n- f: finish（终点场景）\n- ch: character（规划角色，每个章节可包含0-3个）\n- cn: character name（角色名称）\n- cd: character description（该角色在本章的戏份梗概）\n- ci: character importance（重要程度：high/medium/low）\n\n### 格式要求\n1. 直接返回纯XML格式，不要使用markdown代码块标记（不要使用```xml和```）\n2. 不要包含任何解释文字、注释或说明\n3. 只返回XML数据本身\n4. 对于长文本内容（可能包含特殊字符），请使用CDATA标签包裹：<![CDATA[内容]]>\n5. p标签的情节大纲需达到100-150字，概述本章的主要内容和走向\n6. s和f标签的场景描述要具体，包含地点、时间、人物状态\n7. <ch>角色规划标签为可选标签，过渡章节可以不包含角色规划\n8. ci标签只能使用high/medium/low三个值\n\n现在请返回{chapterCount}个章节的完整XML数据（纯XML，不要markdown标记）：', '[{\"desc\":\"卷号\",\"name\":\"volumeNumber\",\"type\":\"integer\",\"required\":true},{\"desc\":\"故事背景\",\"name\":\"projectDescription\",\"type\":\"string\",\"required\":true},{\"desc\":\"故事基调\",\"name\":\"storyTone\",\"type\":\"string\",\"required\":true},{\"desc\":\"故事类型\",\"name\":\"storyGenre\",\"type\":\"string\",\"required\":true},{\"desc\":\"叙事与写作设置\",\"name\":\"narrativeSettings\",\"type\":\"string\",\"required\":false},{\"desc\":\"分卷信息\",\"name\":\"volumeInfo\",\"type\":\"string\",\"required\":true},{\"desc\":\"世界观设定\",\"name\":\"worldviewInfo\",\"type\":\"string\",\"required\":false},{\"desc\":\"登场角色\",\"name\":\"characterInfo\",\"type\":\"string\",\"required\":false},{\"desc\":\"章节数\",\"name\":\"chapterCount\",\"type\":\"integer\",\"required\":true},{\"desc\":\"每章字数\",\"name\":\"wordCount\",\"type\":\"integer\",\"required\":true},{\"desc\":\"章节节奏指导\",\"name\":\"paceGuide\",\"type\":\"string\",\"required\":false}]', 'v2: add character planning output instructions and XML tags (Phase 12)', 1, NULL, NOW());

