UPDATE `ai_prompt_template_version` SET `is_active` = 0 WHERE `id` = 6 AND `template_id` = 6;

-- Update template to use new version
UPDATE `ai_prompt_template` SET `current_version_id` = 20, `updated_time` = NOW() WHERE `id` = 6;
